-- Migración: enriquecer tabla empresa con campos de datos.gov.co
-- y sembrar 200 empresas reales colombianas como catálogo base.
-- Fecha: 2026-05-13

begin;

-- 1. Nuevas columnas en empresa
alter table public.empresa
  add column if not exists nit              text,
  add column if not exists ciudad           text,
  add column if not exists departamento     text,
  add column if not exists rep_legal        text,
  add column if not exists website          text,
  add column if not exists tipo_organizacion text,
  add column if not exists es_pyme          boolean not null default false;

-- Índice único sobre NIT (nullable: solo aplica cuando no es NULL)
create unique index if not exists empresa_nit_unique_idx
  on public.empresa (nit)
  where nit is not null;

-- 2. Seed: 200 empresas reales de datos.gov.co (SECOP)
--    Columnas: nombre_empresa, sector, tamaño_empresa, email_contacto,
--              telefono, descripcion, nit, ciudad, departamento,
--              rep_legal, website, tipo_organizacion, es_pyme, estado, fecha_registro
insert into public.empresa (
  nombre_empresa,
  sector,
  "tamaño_empresa",
  email_contacto,
  telefono,
  descripcion,
  nit,
  ciudad,
  departamento,
  rep_legal,
  website,
  tipo_organizacion,
  es_pyme,
  estado,
  fecha_registro
)
